function mostrarPreu(data) {
    setText('resumenReserva', `Duración de la reserva: ${data.diasReserva} días`, true);
    const lineas = data.lineas;
    const tarifa = findLinea(lineas, [
        'RESERVA_FINGUER',
        'RESERVA_FINGUER_GOLD',
    ]);
    const limpieza = findLinea(lineas, [
        'LIMPIEZA_EXT',
        'LIMPIEZA_EXT_INT',
        'LIMPIEZA_PRO',
    ]);
    const seguro = findLinea(lineas, ['SEGURO_CANCELACION']);
    if (tarifa)
        setText('costeReserva', `Reserva: ${eur(tarifa.base)} (sin IVA)`, true);
    else
        setText('costeReserva', '', false);
    if (seguro)
        setText('costeSeguro', `Seguro: ${eur(seguro.base)} (sin IVA)`, true);
    else
        setText('costeSeguro', `Seguro: No contratado`, true);
    if (limpieza)
        setText('costeLimpieza', `Limpieza: ${eur(limpieza.base)} (sin IVA)`, true);
    else
        setText('costeLimpieza', `Limpieza: No contratada`, true);
    setText('subTotal', `Subtotal: ${eur(data.subtotal)} (sin IVA)`, true);
    setText('precio_iva', `IVA: ${eur(data.iva_total)}`, true);
    setText('total', `Total: ${eur(data.total)}`, true);
}


